CREATE TABLE sakila.staff_ext (
  "ACTIVE" NUMBER(3,0),
  "ADDRESS_ID" NUMBER(5,0),
  "EMAIL" VARCHAR2(50 CHAR),
  "FIRST_NAME" VARCHAR2(45 CHAR),
  "LAST_NAME" VARCHAR2(45 CHAR),
  "LAST_UPDATE" DATE,
  "PASSWORD" VARCHAR2(40 CHAR),
  "PICTURE" BLOB,
  "STAFF_ID" NUMBER(3,0),
  "STORE_ID" NUMBER(3,0),
  "USERNAME" VARCHAR2(16 CHAR))
ORGANIZATION EXTERNAL
(TYPE oracle_loader
DEFAULT DIRECTORY sakila_data_dir
ACCESS PARAMETERS (
RECORDS DELIMITED BY '<EORD>'
BADFILE sakila_log_dir:'sakila.staff.bad'
LOGFILE sakila_log_dir:'sakila.staff.log'
FIELDS TERMINATED BY '<EOFD>'
MISSING FIELD VALUES ARE NULL
("ACTIVE", 
"ADDRESS_ID", 
"EMAIL", 
"FIRST_NAME", 
"LAST_NAME", 
"LAST_UPDATE" CHAR date_format TIMESTAMP mask "yyyy-mm-dd HH24:mi:ss.ff3", 
"PASSWORD", 
"PICTURE", 
"STAFF_ID", 
"STORE_ID", 
"USERNAME"
))
LOCATION ('staff.txt'))
REJECT LIMIT UNLIMITED;

INSERT into sakila.staff (SELECT * from sakila.staff_ext);
commit;

-- drop table sakila.staff_ext;

